<template>
  <div class="w-100">
    <canvas id="myChart"></canvas>
  </div>
</template>

<script>
import {onMounted,reactive} from 'vue'
import {Chart} from 'chart.js/auto'
import {getRelativePosition} from 'chart.js/helpers'
import axios from 'axios'
export default {
    name:'MyChart',
    setup(){
        let salesData =reactive({items:{}})
        onMounted(()=>{
            const ctx = document.getElementById('myChart');
            const chart= new Chart(ctx, {
            type: 'bar',
            data: {
                labels: ['週日', '週一', '週二', '週三', '週四', '週五','週六'],
                datasets: [{
                label: '每日銷售總額',
                data: [12, 19, 3, 5, 2, 3],
                borderWidth: 1
                }]
            },
            options: {
                scales: {
                y: {
                    beginAtZero: true
                }
                },
                onClick: (e) => {
                const canvasPosition = getRelativePosition(e, chart);

                // Substitute the appropriate scale IDs
                const dataX = chart.scales.x.getValueForPixel(canvasPosition.x);
                const dataY = chart.scales.y.getValueForPixel(canvasPosition.y);
                dataX,dataY
                }
            }
            });

            axios.post('/getweeklysalesamount',{'hello':'hello'},{headers:{'contentType':'application/json'}}).then(
                response =>{
                    salesData.items=response.data
                    
                    console.log(new Date(salesData.items[0].orderDay).getDay())
                }
            ).catch(
                error => {
                    console.log(error.message)
                }
            )
            
        })

    }

}
</script>

